import{_ as e,c as d,a as i,o as a}from"./app-CEcM0piI.js";const s={};function r(n,t){return a(),d("div",null,t[0]||(t[0]=[i('<table><thead><tr><th>函数或宏</th><th>含义</th></tr></thead><tbody><tr><td>project(项目名)</td><td>设置项目名,也可以在后面添加一个参数如:LANGUASGES CXX设置此项目是使用c++语言</td></tr><tr><td>add_library(项目名 资源文件)</td><td>将资源文件制作成静态库,指定项目名称</td></tr><tr><td>target_link_libraries(项目名 动态库名)</td><td>将目标项目连接到指定的动态库</td></tr><tr><td>宏PROJECT_NAME</td><td>项目名,project中设置的</td></tr><tr><td>宏CMAKE_PREFIX_PATH</td><td>库文件所在位置,需要使用set设置</td></tr><tr><td>宏CMAKE_AUTOUIC</td><td>自动添加qt文件</td></tr><tr><td>宏CMAKE_AUTOMOC</td><td></td></tr><tr><td>宏CMAKE_AUTORCC</td><td>自动添加qt资源文件</td></tr><tr><td>find_package()</td><td>插入需要引用的包,如qt的Widget核心</td></tr><tr><td>add_compile_options()</td><td>添加编译设置,gcc编译器一般不用,msvc默认编码是gbk可以使用此函数设置为utf-8,如果是gcc编译器则自动忽略此选项</td></tr><tr><td>target_link_libraries(项目名 权限 库名)</td><td>链接动态库</td></tr><tr><td>add_executable(项目名 选项 生成可执行文件的源文件)</td><td>生成以项目名为可执行程序,选项可以使用WIN32,添加后运行程序会弹出终端,不使用则不弹出</td></tr></tbody></table><p><strong>将msvc编译器默认编码设置为utf-8</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>add_compile_options(&quot;$&lt;$&lt;C_COMPILER_ID:MSVC&gt;:/utf-8&gt;&quot;)</span></span>\n<span class="line"><span>add_compile_options(&quot;$&lt;$&lt;CXX_cOMPILER_ID:MSVC&gt;:/utf-8&gt;&quot;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>链接qt的Widget库</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>target_link_libraries(${PROJECT_NAME} PRIVATE Qt6::Widgets)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div>',5)]))}const c=e(s,[["render",r]]),o=JSON.parse('{"path":"/cpp/cmake/4/","title":"4 cmake函数","lang":"zh-CN","frontmatter":{"title":"4 cmake函数","createTime":"2025/04/05 12:12:26","permalink":"/cpp/cmake/4/"},"readingTime":{"minutes":1.05,"words":315},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/C++/cmake/4 cmake函数.md","headers":[]}');export{c as comp,o as data};
